import React, { useState, useEffect, useCallback, useRef } from 'react';
import { DataTable } from 'primereact/datatable';
import { Column } from 'primereact/column';
import { InputNumber } from 'primereact/inputnumber';
import { Dropdown } from 'primereact/dropdown';
import { Button } from 'primereact/button';
import { Card } from 'primereact/card';
import { Tag } from 'primereact/tag';
import { Toast } from 'primereact/toast';
import { ProgressBar } from 'primereact/progressbar';
import { getLoanTypes, grantLoan, getLoansByClient, getRepaymentPlan, payInstalment } from '../api';
import { LoanType, Loan, RepaymentInstalment } from '../types';
import './LoansPage.css';

const CATEGORY_OPTIONS = [
  { label: 'Consumer', value: 'CONSUMER' },
  { label: 'Mortgage', value: 'MORTGAGE' },
];

// ── Inline repayment plan (row expansion) ─────────────────────────────────────

const RepaymentPlanInline: React.FC<{
  loanId: number;
  toast: React.RefObject<Toast>;
}> = ({ loanId, toast }) => {
  const [plan, setPlan] = useState<RepaymentInstalment[]>([]);
  const [loading, setLoading] = useState(true);
  const [payingMonth, setPayingMonth] = useState<number | null>(null);

  const loadPlan = useCallback(async () => {
    setLoading(true);
    try { setPlan(await getRepaymentPlan(loanId)); }
    catch (e: any) { toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message }); }
    finally { setLoading(false); }
  }, [loanId, toast]);

  useEffect(() => { loadPlan(); }, [loadPlan]);

  const handlePay = async (inst: RepaymentInstalment) => {
    setPayingMonth(inst.monthNumber);
    try {
      await payInstalment(loanId, inst.monthNumber);
      await loadPlan();
      toast.current?.show({ severity: 'success', summary: 'Paid', detail: `Month ${inst.monthNumber} marked as paid.` });
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setPayingMonth(null);
    }
  };

  const paid = plan.filter((i) => i.paid).length;
  const pct = plan.length > 0 ? Math.round((paid / plan.length) * 100) : 0;
  const fmtBGN = (v: number) => `BGN ${v.toFixed(2)}`;

  const statusBody = (row: RepaymentInstalment) =>
    row.paid ? <Tag severity="success" value="Paid" /> : <Tag severity="warning" value="Unpaid" />;

  const actionBody = (row: RepaymentInstalment) =>
    row.paid ? null : (
      <Button
        label="Pay"
        icon="pi pi-check"
        size="small"
        loading={payingMonth === row.monthNumber}
        onClick={() => handlePay(row)}
      />
    );

  if (loading) return <ProgressBar mode="indeterminate" style={{ height: 4 }} />;

  return (
    <div className="lp-plan-inline">
      <div className="lp-plan-progress">
        <span>{paid} of {plan.length} instalments paid ({pct}%)</span>
        <ProgressBar value={pct} style={{ height: 8, marginTop: 6 }} />
      </div>
      <DataTable
        value={plan}
        size="small"
        scrollable
        scrollHeight="360px"
        stripedRows
        rowClassName={(row: RepaymentInstalment) => ({ 'lp-row-paid': row.paid })}
      >
        <Column field="monthNumber" header="Month" style={{ width: 70 }} />
        <Column field="totalPayment" header="Total Payment" body={(r) => fmtBGN(r.totalPayment)} />
        <Column field="principalPart" header="Principal" body={(r) => fmtBGN(r.principalPart)} />
        <Column field="interestPart" header="Interest" body={(r) => fmtBGN(r.interestPart)} />
        <Column field="remainingBalance" header="Remaining Balance" body={(r) => fmtBGN(r.remainingBalance)} />
        <Column header="Status" body={statusBody} style={{ width: 90 }} />
        <Column header="Action" body={actionBody} style={{ width: 90 }} />
      </DataTable>
    </div>
  );
};

// ── Loan Type Info Cards ──────────────────────────────────────────────────────

const LoanTypeCards: React.FC = () => {
  const [types, setTypes] = useState<LoanType[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getLoanTypes()
      .then(setTypes)
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <ProgressBar mode="indeterminate" style={{ height: 4, marginBottom: 16 }} />;

  return (
    <div className="lp-type-cards">
      {types.map((lt) => (
        <div key={lt.id} className={`lp-type-card lp-type-card--${lt.category.toLowerCase()}`}>
          <div className="lp-type-icon">
            {lt.category === 'CONSUMER'
              ? <i className="pi pi-credit-card" style={{ fontSize: 28 }} />
              : <i className="pi pi-home" style={{ fontSize: 28 }} />}
          </div>
          <div className="lp-type-label">{lt.category === 'CONSUMER' ? 'Consumer Loan' : 'Mortgage Loan'}</div>
          <div className="lp-type-stats">
            <div className="lp-type-stat">
              <span className="lp-stat-label">Annual Rate</span>
              <span className="lp-stat-value lp-rate">{(lt.annualInterestRate * 100).toFixed(2)}%</span>
            </div>
            <div className="lp-type-stat">
              <span className="lp-stat-label">Max Amount</span>
              <span className="lp-stat-value">BGN {lt.maxAmount.toLocaleString()}</span>
            </div>
            <div className="lp-type-stat">
              <span className="lp-stat-label">Max Term</span>
              <span className="lp-stat-value">{lt.maxTermMonths} months</span>
            </div>
          </div>
        </div>
      ))}
    </div>
  );
};

// ── Main Page ─────────────────────────────────────────────────────────────────

const LoansPage: React.FC = () => {
  const toast = useRef<Toast>(null);

  // ── Grant form ────────────────────────────────────────────────────────────
  const [grantClientId, setGrantClientId] = useState<number | null>(null);
  const [category, setCategory] = useState<'CONSUMER' | 'MORTGAGE'>('CONSUMER');
  const [amount, setAmount] = useState<number | null>(null);
  const [termMonths, setTermMonths] = useState<number | null>(null);
  const [granting, setGranting] = useState(false);

  // ── Search ────────────────────────────────────────────────────────────────
  const [searchId, setSearchId] = useState<number | null>(null);
  const [loans, setLoans] = useState<Loan[]>([]);
  const [searching, setSearching] = useState(false);
  const [hasSearched, setHasSearched] = useState(false);
  const [expandedRows, setExpandedRows] = useState<any>(null);

  const loadLoans = useCallback(async (id: number) => {
    setSearching(true);
    try { setLoans(await getLoansByClient(id)); }
    catch (e: any) { toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message }); setLoans([]); }
    finally { setSearching(false); }
  }, []);

  const handleSearch = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!searchId || searchId <= 0) {
      toast.current?.show({ severity: 'warn', summary: 'Validation', detail: 'Enter a valid Client ID.' });
      return;
    }
    setHasSearched(true);
    setExpandedRows(null);
    await loadLoans(searchId);
  };

  const handleGrant = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!grantClientId || !amount || !termMonths) {
      toast.current?.show({ severity: 'warn', summary: 'Validation', detail: 'All fields are required.' });
      return;
    }
    setGranting(true);
    try {
      const loan = await grantLoan({ clientId: grantClientId, loanCategory: category, amount, termMonths });
      toast.current?.show({
        severity: 'success',
        summary: 'Loan Granted',
        detail: `Loan #${loan.id} — BGN ${loan.amount.toFixed(2)} for ${loan.termMonths} months.`,
      });
      setGrantClientId(null);
      setAmount(null);
      setTermMonths(null);
      if (searchId === grantClientId) await loadLoans(grantClientId);
    } catch (e: any) {
      toast.current?.show({ severity: 'error', summary: 'Error', detail: e.message });
    } finally {
      setGranting(false);
    }
  };

  const categoryBody = (row: Loan) => (
    <Tag value={row.loanCategory} severity={row.loanCategory === 'CONSUMER' ? 'info' : 'warning'} />
  );

  const progressBody = (row: Loan) => {
    const pct = row.totalInstalments > 0
      ? Math.round((row.paidInstalments / row.totalInstalments) * 100)
      : 0;
    return (
      <div className="lp-progress-cell">
        <span>{row.paidInstalments}/{row.totalInstalments}</span>
        <div className="lp-mini-bar">
          <div className="lp-mini-fill" style={{ width: `${pct}%` }} />
        </div>
      </div>
    );
  };

  const rowExpansionTemplate = (row: Loan) => (
    <RepaymentPlanInline loanId={row.id} toast={toast} />
  );

  return (
    <div className="lp-page">
      <Toast ref={toast} />
      <div className="lp-page-header">
        <h1 className="lp-page-title">Loans</h1>
        <p className="lp-page-subtitle">Grant and manage client loan products</p>
      </div>

      <section className="lp-section">
        <h2 className="lp-section-title">Available Loan Products</h2>
        <LoanTypeCards />
      </section>

      <div className="lp-top-grid">
        {/* Grant form */}
        <Card title="Grant New Loan" className="lp-card">
          <form className="lp-form" onSubmit={handleGrant}>
            <div className="lp-form-grid">
              <div className="lp-field">
                <label>Client ID</label>
                <InputNumber
                  value={grantClientId}
                  onValueChange={(e) => setGrantClientId(e.value ?? null)}
                  placeholder="e.g. 1"
                  min={1}
                  disabled={granting}
                  useGrouping={false}
                />
              </div>
              <div className="lp-field">
                <label>Category</label>
                <Dropdown
                  value={category}
                  options={CATEGORY_OPTIONS}
                  onChange={(e) => setCategory(e.value)}
                  disabled={granting}
                />
              </div>
              <div className="lp-field">
                <label>Amount (BGN)</label>
                <InputNumber
                  value={amount}
                  onValueChange={(e) => setAmount(e.value ?? null)}
                  placeholder="e.g. 10000"
                  min={1}
                  minFractionDigits={2}
                  maxFractionDigits={2}
                  disabled={granting}
                  useGrouping={false}
                />
              </div>
              <div className="lp-field">
                <label>Term (months)</label>
                <InputNumber
                  value={termMonths}
                  onValueChange={(e) => setTermMonths(e.value ?? null)}
                  placeholder="e.g. 36"
                  min={1}
                  disabled={granting}
                  useGrouping={false}
                />
              </div>
            </div>
            <Button
              type="submit"
              label="Grant Loan"
              icon="pi pi-send"
              loading={granting}
              className="lp-submit-btn"
            />
          </form>
        </Card>

        {/* Search form */}
        <Card title="Find Loans by Client" className="lp-card">
          <form className="lp-search-form" onSubmit={handleSearch}>
            <div className="lp-field">
              <label>Client ID</label>
              <InputNumber
                value={searchId}
                onValueChange={(e) => setSearchId(e.value ?? null)}
                placeholder="Enter Client ID"
                min={1}
                disabled={searching}
                useGrouping={false}
              />
            </div>
            <Button
              type="submit"
              label="Load Loans"
              icon="pi pi-search"
              loading={searching}
              className="lp-submit-btn"
            />
          </form>
        </Card>
      </div>

      {hasSearched && (
        <Card title={`Loans — Client #${searchId}`} className="lp-results-card">
          <DataTable
            value={loans}
            loading={searching}
            expandedRows={expandedRows}
            onRowToggle={(e) => setExpandedRows(e.data)}
            rowExpansionTemplate={rowExpansionTemplate}
            dataKey="id"
            stripedRows
            paginator
            rows={10}
            emptyMessage="No loans found for this client."
          >
            <Column expander style={{ width: 40 }} />
            <Column field="id" header="ID" style={{ width: 70 }} body={(r) => `#${r.id}`} sortable />
            <Column header="Category" body={categoryBody} style={{ width: 130 }} />
            <Column field="amount" header="Amount" body={(r: Loan) => `BGN ${r.amount.toFixed(2)}`} sortable />
            <Column field="termMonths" header="Term" body={(r: Loan) => `${r.termMonths} mo.`} style={{ width: 90 }} sortable />
            <Column header="Progress" body={progressBody} style={{ width: 160 }} />
          </DataTable>
        </Card>
      )}
    </div>
  );
};

export default LoansPage;
